A = (25, 0) * dir(-20);
B = (15, 0) * dir(60);
C = (25, 0) * dir(160);
D = (15, 0) * dir(-120);
pM = 0.5 * A + 0.5 * B;
pN = 0.5 * B + 0.5 * C;
O = 0.25 * A + 0.25 * B + 0.25 * C + 0.25 * D;
P = 0.33 * C + 0.67 * A;
Q = 0.67 * C + 0.33 * A;
draw(A--B--C--D--cycle);
